public class Triangulo extends FiguraGeometrica{    private Punto punto1;    private Punto punto2;    private Punto punto3;    @Override    public String toString() {        return "Triangulo{" +                "punto1=" + punto1 +                ", punto2=" + punto2 +                ", punto3=" + punto3 +                ", Nombre=" +getNombre() +                '}';    }    public Punto getPunto1() {        return punto1;    }    public void setPunto1(Punto punto1) {        this.punto1 = punto1;    }    public Punto getPunto2() {        return punto2;    }    public void setPunto2(Punto punto2) {        this.punto2 = punto2;    }    public Punto getPunto3() {        return punto3;    }    public void setPunto3(Punto punto3) {        this.punto3 = punto3;    }    @Override    public double calcularAreaFigura() {        return 0;    }    @Override    public boolean esRegular() {        return false;    }}